# Azure Policy: enforce a naming convention with a Deny effect

# Example: resource groups must match pattern 'rg-*-{prod|dev|stg}'
POLICY_RULE='{
  "if": {
    "allOf": [
      {"field": "type", "equals": "Microsoft.Resources/subscriptions/resourceGroups"},
      {"not": {"field": "name", "match": "rg-?*-[proddevstg]*"}}
    ]
  },
  "then": {"effect": "deny"}
}'

az policy definition create \
  --name 'require-rg-naming-convention' \
  --mode All \
  --rules "$POLICY_RULE"

az policy assignment create \
  --name 'require-rg-naming-convention' \
  --scope /subscriptions/<subId> \
  --policy require-rg-naming-convention

# Policy 'match' pattern wildcards:
# ?  — matches any single character
# *  — matches zero or more characters
# [abc] — matches one of the listed characters

// Bicep: centralise naming logic in a naming module

// naming.bicep — call this once and reference outputs throughout
@description('Short workload abbreviation (e.g. myapp, payments)')
param workload string

@description('Environment: prod | dev | stg')
@allowed(['prod', 'dev', 'stg'])
param env string

@description('Short region code, e.g. eus2, weu')
param region string

param instance string = '001'

output vmName string = 'vm-${workload}-${env}-${region}-${instance}'
output rgName string = 'rg-${workload}-${env}-${region}'
// Storage accounts: no hyphens, lowercase, max 24
output storageAccountName string = 'st${workload}${env}${region}${instance}'
output keyVaultName string = 'kv-${workload}-${env}-${region}'
output aksName string = 'aks-${workload}-${env}-${region}'
output acrName string = 'cr${workload}${env}${region}'

// Usage in main.bicep:
// module names 'naming.bicep' = {
//   name: 'naming'
//   params: { workload: 'myapp', env: 'prod', region: 'eus2' }
// }
// resource vm 'Microsoft.Compute/virtualMachines@2023-03-01' = {
//   name: names.outputs.vmName  // vm-myapp-prod-eus2-001
// }

import re

RULES = {
    'Microsoft.Compute/virtualMachines': {
        'max_len': 64, 'min_len': 1,
        'pattern': r'^[a-zA-Z][a-zA-Z0-9-]*$',
        'global_unique': False,
    },
    'Microsoft.Storage/storageAccounts': {
        'max_len': 24, 'min_len': 3,
        'pattern': r'^[a-z0-9]+$',
        'global_unique': True,
    },
    'Microsoft.KeyVault/vaults': {
        'max_len': 24, 'min_len': 3,
        'pattern': r'^[a-zA-Z][a-zA-Z0-9-]+$',
        'global_unique': True,
    },
}

def validate_name(resource_type: str, name: str) -> list[str]:
    rule = RULES.get(resource_type)
    if not rule:
        return [f'No validation rules for {resource_type}']
    errors = []
    if len(name) < rule['min_len'] or len(name) > rule['max_len']:
        errors.append(f'Length {len(name)} out of range [{rule["min_len"]}-{rule["max_len"]}]')
    if not re.match(rule['pattern'], name):
        errors.append(f'Name does not match pattern {rule["pattern"]}')
    return errors

# Examples
print(validate_name('Microsoft.Storage/storageAccounts', 'my-storage-acct'))  # Error: hyphens not allowed
print(validate_name('Microsoft.Storage/storageAccounts', 'stmyappprodeus2001'))  # OK
print(validate_name('Microsoft.KeyVault/vaults', 'kv-myapp-prod-eus2'))  # OK

# PowerShell function: generate a CAF-compliant resource name
function Get-AzResourceName {
    param(
        [string] $ResourceType,  # 'vm', 'st', 'kv', 'vnet', 'nsg'
        [string] $Workload,
        [string] $Environment,   # 'prod', 'dev', 'stg'
        [string] $Region,        # 'eus2', 'weu'
        [string] $Instance = '001'
    )

    # Storage accounts: no hyphens, lowercase, max 24
    if ($ResourceType -eq 'st') {
        $name = ("$ResourceType$Workload$Environment$Region$Instance").ToLower()
        if ($name.Length -gt 24) { throw "Storage name too long: $name" }
        return $name
    }

    # Container Registry: no hyphens
    if ($ResourceType -eq 'cr') {
        return ("$ResourceType$Workload$Environment$Region").ToLower()
    }

    # Standard hyphen-separated name
    return "$ResourceType-$Workload-$Environment-$Region-$Instance"
}

# Usage:
Get-AzResourceName -ResourceType 'vm'  -Workload 'myapp' -Environment 'prod' -Region 'eus2'
# vm-myapp-prod-eus2-001

Get-AzResourceName -ResourceType 'st'  -Workload 'myapp' -Environment 'prod' -Region 'eus2'
# stmyappprodeus2001

Get-AzResourceName -ResourceType 'kv'  -Workload 'myapp' -Environment 'prod' -Region 'eus2'
# kv-myapp-prod-eus2-001
